class FoodstuffsForm{constructor(form){this.formName=form.attr("name");this.errors=$("#form_errors_client");this.weightsNumber=$(".foodstuff-weight").length-1;$(".food-unit").each((index,element)=>{let pieceName=$(element).data("piece-name");$(element).children().each((choiceIndex,choice)=>{if($(choice).val()==="stuks"&&pieceName!==""){$(choice).text(pieceName)}})});$("#add_foodstuff").on("click",this.addFoodstuff.bind(this));form.on("input",".foodstuff-name",this.foodstuffNameInput.bind(this));form.on("click",".foodstuff-result",this.foodstuffSearchResultClick.bind(this));form.on("click",".remove-row",this.removeRow.bind(this));form.on("submit",this.submit.bind(this))}addFoodstuff(event){this.weightsNumber=this.weightsNumber+1;let html='<tr><td><div class="dropdown">'+$("#"+this.formName+"_foodstuff_weights__name___name").data("prototype")+'<div class="dropdown-menu dropdown-menu-foodstuff"></div></div>'+$("#"+this.formName+"_foodstuff_weights__name___foodstuff_id").data("prototype")+"</td>";html+="<td>"+$("#"+this.formName+"_foodstuff_weights__name___value").data("prototype")+"</td>";if(this.formName==="foodstuff_from_foodstuffs"){html+="<td>%</td>"}else{html+="<td>"+$("#"+this.formName+"_foodstuff_weights__name___unit").data("prototype")+"</td>"}html+='<td><i class="remove-row fa fa-minus"></i></td></tr>';$("#add_foodstuff_recipe_button_row").before(html);$('[name="'+this.formName+'[foodstuff_weights][__name__][foodstuff_id]"]').attr("name",this.formName+"[foodstuff_weights]["+this.weightsNumber+"][foodstuff_id]").removeAttr("id");$('[name="'+this.formName+'[foodstuff_weights][__name__][name]"]').attr("name",this.formName+"[foodstuff_weights]["+this.weightsNumber+"][name]").removeAttr("id");$('[name="'+this.formName+'[foodstuff_weights][__name__][value]"]').attr("name",this.formName+"[foodstuff_weights]["+this.weightsNumber+"][value]").removeAttr("id");$('[name="'+this.formName+'[foodstuff_weights][__name__][unit]"]').attr("name",this.formName+"[foodstuff_weights]["+this.weightsNumber+"][unit]").removeAttr("id");event.preventDefault()}foodstuffNameInput(event){let thisElement=$(event.target);let row=new this.FoodstuffRow(event.target);let valueInput=encodeURI(thisElement.val().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,""));let searchResults=row.getSearchResults();searchResults.html("");let url;url=$("#foodstuff_search").data("search").replace("__name__",valueInput);if(this.timeout){clearTimeout(this.timeout);this.timeout=null}this.timeout=setTimeout(()=>{$.ajax({url:url,type:"GET",success:data=>{if(valueInput!==""){searchResults.html(data)}else{searchResults.html("")}$(".foodstuff-result").each((index,element)=>{let id=$(element).attr("id").replace("foodstuff_result_","");let name=$(element).text().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");if(valueInput===name){this.setIdAndUnit(row,id,$(element))}})},error:()=>{searchResults.html("Er ging iets fout.")}})},1e3)}setIdAndUnit(row,id,element){row.getFoodstuffId().val(id);let pieceName=element.data("piece-name");let pieceWeight=element.data("piece-weight");row.getUnit().val("g");if(element.data("is-liquid")===0){row.getUnit().addClass("not-liquid")}else{row.getUnit().removeClass("not-liquid")}if(element.data("piece-weight")===""){row.getUnit().addClass("not-piece")}else{row.getUnit().removeClass("not-piece")}if(pieceName!==""){row.getUnitPiece().text(pieceName);row.getUnit().val("stuks")}else if(pieceWeight!==""){row.getUnit().val("stuks")}}foodstuffSearchResultClick(event){let thisElement=$(event.target);let row=new this.FoodstuffRow(event.target);let id=thisElement.attr("id").replace("foodstuff_result_","");let name=thisElement.text();row.getName().val(name);this.setIdAndUnit(row,id,thisElement)}removeRow(event){new this.FoodstuffRow(event.target).row.remove()}submit(event){let text="";let foodstuffNames=[];$(".foodstuff-name").each((index,element)=>{if(foodstuffNames.includes($(element).val())){text=text+"Dubbel voedingsmiddel. <br>";event.preventDefault()}foodstuffNames.push($(element).val())});if(this.formName==="foodstuff_from_foodstuffs"){let sum=0;$(".foodstuff-weight").each((index,element)=>{sum=sum+parseFloat($(element).val().replace(",","."))});if(Math.round(sum*100)!==1e4){text=text+"De gewichten zijn samen niet gelijk aan 100%. <br>";event.preventDefault()}}this.errors.html(text)}FoodstuffRow=class{constructor(thisElement){this.row=$(thisElement).closest("tr")}getFoodstuffId(){return this.row.find(".foodstuff-id")}getName(){return this.row.find(".dropdown-toggle")}getWeight(){return this.row.find(".foodstuff-weight")}getUnit(){return this.row.find(".foodstuff-unit")}getUnitPiece(){return this.row.find(".foodstuff-unit .piece-option")}getSearchResults(){return this.row.find(".dropdown-menu-foodstuff")}}}